<template>
    <div>
        <el-form inline>
            <el-form-item v-for="(i, index) in items" :key="index">
                <el-checkbox v-model="i.show" border>{{i.w}} : {{i.h}} {{i.c}}英寸 宽{{wcm(i)}} 高{{hcm(i)}}</el-checkbox>
            </el-form-item>
        </el-form>
        <div v-for="(i, index) in items" :key="index">
            <div v-if="i.show" :style="style(i)"></div>
        </div>
    </div>
</template>
<script>
    export default {
        data() {
            return {
                items: [
                    {w: 16, h: 9, c: 27},
                    {w: 16, h: 9, c: 31.5},
                    {w: 16, h: 9, c: 42.5},
                    {w: 21, h: 9, c: 34},
                    {w: 21, h: 9, c: 37.5},
                    {w: 32, h: 9, c: 49},
                    {w: 32, h: 10, c: 43},
                ]
            }
        },
        methods: {
            style(o) {
                return {
                    width: o.w * this.unit(o) * 18 + 'px',
                    height: o.h * this.unit(o) * 18 + 'px',
                    border: '1px solid',
                    position: 'absolute',
                    left: '200px',
                    bottom: '100px'
                }
            },
            unit(o) { // 计算一个单位代表几英寸
                return o.c / Math.sqrt(Math.pow(o.w, 2) + Math.pow(o.h, 2))
            },
            // 1英寸=2.54厘米
            wcm(o) {
                return (o.w * this.unit(o) * 2.54).toFixed(2) + 'cm';
            },
            hcm(o) {
                return (o.h * this.unit(o) * 2.54).toFixed(2) + 'cm';
            }
        }
    }
</script>
<style scoped>
    .el-input-number {
        width: 75px !important;
    }
</style>
